import React from 'react';
import { Link } from 'react-router-dom';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import 'react-lazy-load-image-component/src/effects/blur.css';

const ProductCard = ({ product, onAddToCart }) => {
  const handleAddToCart = () => {
    if (onAddToCart) onAddToCart(product);
  };

  const discount = product.originalPrice
    ? Math.round(
        ((product.originalPrice - product.price) / product.originalPrice) * 100
      )
    : 0;

  const slug = product.slug || product.productId;

  return (
    <article className="product-card">
      {product.badge && (
        <span className={`product-badge ${product.badge}`}>
          {product.badge === 'new'
            ? 'New'
            : product.badge === 'sale'
              ? 'Sale'
              : product.badge === 'bestseller'
                ? 'Bestseller'
                : product.badge}
        </span>
      )}
      <div className="product-image">
        <Link to={`/shop/${slug}`} className="product-image-link">
          {product.imageUrl ? (
            <LazyLoadImage
              className="product-image__img"
              src={product.imageUrl}
              alt={product.name}
              effect="blur"
            />
          ) : (
            <span className="product-image__emoji" aria-hidden>
              {product.emoji || '📦'}
            </span>
          )}
        </Link>
        <button type="button" className="product-quick-add" onClick={handleAddToCart}>
          + Add to Cart
        </button>
      </div>
      <div className="product-info">
        <div className="product-category" style={{ textTransform: 'capitalize' }}>
          {typeof product.category === 'string'
            ? product.category
            : product.category?.slug || ''}
        </div>
        <Link to={`/shop/${slug}`} className="product-name-link">
          <div className="product-name">{product.name}</div>
        </Link>
        <div className="product-rating">
          <span className="stars">
            {'★'.repeat(Math.floor(product.rating || 0))}
            {'☆'.repeat(5 - Math.floor(product.rating || 0))}
          </span>
          <span className="rating-count">({product.ratingCount ?? 0})</span>
        </div>
        <div className="product-price">
          <span className="price-current">£{Number(product.price).toFixed(2)}</span>
          {product.originalPrice != null && (
            <>
              <span className="price-original">£{Number(product.originalPrice).toFixed(2)}</span>
              <span className="price-discount">-{discount}%</span>
            </>
          )}
        </div>
        <div className="product-actions">
          <button type="button" className="btn btn-primary btn-sm btn--flex" onClick={handleAddToCart}>
            Add to Cart
          </button>
        </div>
      </div>
    </article>
  );
};

export default ProductCard;
